<h1 class="h3 mb-3">Reglas de clasificación</h1>
<div class="card mb-4"><div class="card-body"><h2 class="h5">Nueva regla</h2><form method="post" action="?route=rule_save" class="row g-2"><div class="col-md-3"><input name="palabra_clave" class="form-control" placeholder="MERCADONA" required></div><div class="col-md-2"><select name="categoria_id" class="form-select" required><?php foreach ($categories as $c): ?><option value="<?= $c['id'] ?>"><?= e($c['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><select name="subcategoria_id" class="form-select" required><?php foreach ($subcategories as $s): ?><option value="<?= $s['id'] ?>"><?= e($s['categoria'] . ' / ' . $s['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-2"><select name="tipo" class="form-select"><option value="gasto">Gasto</option><option value="ingreso">Ingreso</option><option value="ambos">Ambos</option></select></div><div class="col-md-1"><input name="prioridad" type="number" class="form-control" value="10"></div><div class="col-md-1"><label class="form-check"><input type="checkbox" name="activa" value="1" class="form-check-input" checked> Activa</label></div><div class="col-12"><button class="btn btn-primary">Guardar</button></div></form></div></div>
<div class="card"><div class="table-responsive"><table class="table mb-0"><thead><tr><th>Palabra</th><th>Categoría</th><th>Tipo</th><th>Prioridad</th><th>Activa</th><th></th></tr></thead><tbody><?php foreach ($rules as $r): ?><tr><form method="post" action="?route=rule_save"><input type="hidden" name="id" value="<?= $r['id'] ?>"><td><input name="palabra_clave" value="<?= e($r['palabra_clave']) ?>" class="form-control form-control-sm"></td><td><select name="categoria_id" class="form-select form-select-sm"><?php foreach ($categories as $c): ?><option value="<?= $c['id'] ?>" <?= $c['id']==$r['categoria_id']?'selected':'' ?>><?= e($c['nombre']) ?></option><?php endforeach; ?></select><select name="subcategoria_id" class="form-select form-select-sm mt-1"><?php foreach ($subcategories as $s): ?><option value="<?= $s['id'] ?>" <?= $s['id']==$r['subcategoria_id']?'selected':'' ?>><?= e($s['categoria'] . ' / ' . $s['nombre']) ?></option><?php endforeach; ?></select></td><td><select name="tipo" class="form-select form-select-sm"><option value="gasto" <?= $r['tipo']==='gasto'?'selected':'' ?>>Gasto</option><option value="ingreso" <?= $r['tipo']==='ingreso'?'selected':'' ?>>Ingreso</option><option value="ambos" <?= $r['tipo']==='ambos'?'selected':'' ?>>Ambos</option></select></td><td><input name="prioridad" type="number" value="<?= $r['prioridad'] ?>" class="form-control form-control-sm"></td><td><input type="checkbox" name="activa" value="1" <?= $r['activa']?'checked':'' ?>></td><td><button class="btn btn-sm btn-outline-primary">Editar</button></form><form method="post" action="?route=rule_delete" data-confirm="¿Eliminar regla?" class="d-inline"><input type="hidden" name="id" value="<?= $r['id'] ?>"><button class="btn btn-sm btn-outline-danger">Eliminar</button></form></td></tr><?php endforeach; ?></tbody></table></div></div>
